import{_ as l,c as t,o as r,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.23：桌面版新布局与中文排版修复","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.23.md","filePath":"changelog/v1.1.23.md","lastUpdated":1772014034000}'),o={name:"changelog/v1.1.23.md"};function s(n,i,d,h,c,p){return r(),t("div",null,[...i[0]||(i[0]=[a('<h1 id="v1-1-23-桌面版新布局与中文排版修复" tabindex="-1">v1.1.23：桌面版新布局与中文排版修复 <a class="header-anchor" href="#v1-1-23-桌面版新布局与中文排版修复" aria-label="Permalink to “v1.1.23：桌面版新布局与中文排版修复”">​</a></h1><p><strong>发布日期</strong>：2026年01月16日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新带来了全新的桌面版布局设计，修复了中文在终端下的排版问题，并优化了链接打开方式。</p><hr><h2 id="新功能-桌面版焕新" tabindex="-1">新功能：桌面版焕新 <a class="header-anchor" href="#新功能-桌面版焕新" aria-label="Permalink to “新功能：桌面版焕新”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>OpenCode 桌面版迎来了一次视觉和体验上的大升级，采用了全新的应用布局，并优化了大量 UI 细节。</p><h3 id="细节优化" tabindex="-1">细节优化 <a class="header-anchor" href="#细节优化" aria-label="Permalink to “细节优化”">​</a></h3><ul><li><strong>全新布局</strong>：界面更加整洁现代，操作更顺手。</li><li><strong>状态记忆</strong>：现在会自动记住你工作区的分支选择、文件列表的排序和折叠状态，下次打开还是熟悉的样子。</li><li><strong>视觉微调</strong>：修复了思考动画的透明度、会话图标对齐、背景色等细节问题。</li></ul><h3 id="如何体验" tabindex="-1">如何体验？ <a class="header-anchor" href="#如何体验" aria-label="Permalink to “如何体验？”">​</a></h3><p>直接升级到最新版 OpenCode 桌面应用即可看到变化。</p><hr><h2 id="改进-中文排版修复" tabindex="-1">改进：中文排版修复 <a class="header-anchor" href="#改进-中文排版修复" aria-label="Permalink to “改进：中文排版修复”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在终端界面（TUI）下，中文、日文等宽字符（CJK）有时会出现换行错误或渲染重叠的问题，影响阅读体验。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>升级了底层显示库（OpenTUI v0.1.73），彻底修复了这些问题。现在在终端里看中文内容，排版会更加整齐漂亮。</p><hr><h2 id="改进-链接跳转优化" tabindex="-1">改进：链接跳转优化 <a class="header-anchor" href="#改进-链接跳转优化" aria-label="Permalink to “改进：链接跳转优化”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>在桌面版应用里点击链接（比如文档链接），有时会直接在应用内的一个小窗口打开，浏览体验不够好，也无法使用浏览器的插件。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>现在点击外部链接，会直接唤起你系统的默认浏览器打开。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td><strong>中文用户</strong></td><td>✅ <strong>强烈建议升级</strong>（修复了排版）</td></tr><tr><td>桌面版用户</td><td>✅ 推荐升级（新布局更好用）</td></tr><tr><td>命令行用户</td><td>建议升级</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',29),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Ensure agent exists before processing title in session summary</li><li>More defensive handling of project list to prevent errors</li><li>Filter dead worktrees from git worktree list</li><li>Load models.dev in development mode</li><li>Ensure frontmatter can process same content as other agents</li><li>Show toast error message when ConfigMarkdown parsing fails</li><li>Prettify retry duration display in TUI</li><li>Handle broken symlinks gracefully in grep tool</li><li>Honor per-server MCP timeouts</li><li>Upgrade OpenTUI to v0.1.73, fixing CJK word wrapping</li><li>Add input limit for compaction</li><li>Fix Codex ID issue</li><li>Revert provider-level store option</li><li>Allow provider-level store option</li><li>Make dialog keybinds configurable</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Update black plan selection with light rays effect and mobile styles</li><li>Use native text truncation for sidebar diff paths</li><li>Center the initially selected session in the session list</li><li>Restore brand integrity of TUI wordmark</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix sidebar toggle on desktop</li><li>Persist workspace branch selection across sessions</li><li>Persist workspace order and collapsed state in sidebar</li><li>Fix thinking animation opacity and improve design</li><li>Fix session icon and name alignment</li><li>Show session as busy even when it&#39;s the active session</li><li>Stop killing opencode-cli process on dev mode restart</li><li>Update desktop question tools</li><li>Fix current session background color</li><li>Remove the active state from load more button after press</li><li>Fix new session tooltip position and add keyboard shortcut</li><li>Remove more options tooltip</li><li>Fix workspace name color in UI</li><li>Hide &quot;View all sessions&quot; button when on active project page</li><li>Fix avatar button states</li><li>Reduce font size of load more button</li><li>Fix recent sessions title color</li><li>Fix project dropdown labels and sorting order</li><li>Move left panel toggle button to the right</li><li>Fix avatar background color</li><li>Show project options on hover of row</li><li>Increase delay on session list tooltips</li><li>Fix tooltip gutter spacing on session items and archive buttons</li><li>Archive icon replaces diff count on hover</li><li>Fix hover state for recent sessions in gutter</li><li>Fix search bar functionality in header</li><li>Fixed layout issues in the app</li><li>Fix stale sessions in new layout</li><li>New app layout</li><li>Open external links in system browser instead of webview in desktop app</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=l(o,[["render",s]]);export{m as __pageData,g as default};
